```java
import java.util.*;

public class PagePredictor {
    Map<String, Set<String>> pageMap;
    Map<String, Integer> visitCountMap;

    public PagePredictor() {
        pageMap = new HashMap<>();
        visitCountMap = new HashMap<>();
    }

    public void addPage(String pageName, Set<String> resources) {
        pageMap.put(pageName, resources);
        visitCountMap.put(pageName, 0);
    }

    public void logPageVisit(String pageName) {
        visitCountMap.put(pageName, visitCountMap.get(pageName) + 1);
    }

    public Set<String> predictNextPage(String currentPage) {
        // Build a graph using the pageMap and compute shortest distances
        Map<String, Integer> distances = computeShortestDistances(currentPage);

        // Sort all of the pages by their distance, and select the ones that are
        // reachable from the current page.
        List<String> pageList = new ArrayList<>(pageMap.keySet());
        Collections.sort(pageList, Comparator.comparingInt(distances::get));
        int currentIndex = pageList.indexOf(currentPage);
        Set<String> reachablePages = new HashSet<>();

        for (int i = currentIndex + 1; i < pageList.size(); i++) {
            String nextPage = pageList.get(i);
            if (distances.get(nextPage) == Integer.MAX_VALUE) {
                break;
            }
            reachablePages.add(nextPage);
        }

        // Sort the reachable pages by their visit count, and return the one with the
        // highest count.
        List<String> reachablePageList = new ArrayList<>(reachablePages);
        Collections.sort(reachablePageList, Comparator.comparingInt(visitCountMap::get).reversed());
        return pageMap.get(reachablePageList.get(0));
    }

    private Map<String, Integer> computeShortestDistances(String startPage) {
        Map<String, Integer> distances = new HashMap<>();
        for (String pageName : pageMap.keySet()) {
            distances.put(pageName, Integer.MAX_VALUE);
        }
        distances.put(startPage, 0);

        Set<String> visited = new HashSet<>();
        visited.add(startPage);

        Queue<String> queue = new LinkedList<>();
        queue.add(startPage);

        while (!queue.isEmpty()) {
            String currentPage = queue.poll();

            for (String nextPage : pageMap.get(currentPage)) {
                int distance = distances.get(currentPage) + 1;
                if (distance < distances.get(nextPage)) {
                    distances.put(nextPage, distance);
                }

                if (!visited.contains(nextPage)) {
                    visited.add(nextPage);
                    queue.add(nextPage);
                }
            }
        }

        return distances;
    }
}
```

在这个实现中，函数 `addPage` 用于添加一个页面和它包含的资源列表。函数 `logPageVisit` 用于记录用户访问一个页面。函数 `predictNextPage` 根据当前页面的访问记录和页面之间关系，预测下一个可能访问的页面，并返回该页面的资源列表。

需要注意的是，在实现过程中，距离计算时使用了广度优先搜索算法，预测下一个页面时对距离和访问计数进行了排序和筛选，以提高预测的准确性和实用性。

此外，在实现过程中，你可能需要考虑一些其他的细节问题，比如如何处理循环引用等场景。

