```kotlin
class PagePredictor(private val pages: List<String>) {
    private val graph: MutableMap<String, MutableSet<String>> = mutableMapOf()
    private val visitCountMap: MutableMap<String, Int> = mutableMapOf()
    private val sequence: LinkedList<String> = LinkedList()

    init {
        for (page in pages) {
            graph[page] = mutableSetOf()
            visitCountMap[page] = 0
        }
    }

    fun addPage(pageName: String, resources: Set<String>) {
        graph[pageName]?.addAll(resources)
    }

    fun logPageVisit(pageName: String) {
        visitCountMap[pageName] = visitCountMap[pageName]?.plus(1) ?: 1
        sequence.add(pageName)
    }

    fun predictNextPage(currentPage: String): Set<String> {
        val distances = getDistances(currentPage)
        val reachablePages = getReachablePages(currentPage, distances)
        val mostVisitedNextPage = getMostVisitedNextPage(reachablePages)
        return graph[mostVisitedNextPage] ?: emptySet<String>()
    }

    private fun getDistances(startPage: String): MutableMap<String, Int> {
        val distances = mutableMapOf<String, Int>()
        for (page in pages) {
            distances[page] = Integer.MAX_VALUE
        }
        distances[startPage] = 0

        val visited = mutableSetOf<String>()
        visited.add(startPage)

        val queue = LinkedList<String>()
        queue.add(startPage)

        while (queue.isNotEmpty()) {
            val currentPage = queue.poll()
            for (nextPage in graph[currentPage] ?: emptySet()) {
                val distance = distances[currentPage]!! + 1
                if (distance < distances[nextPage]!!) {
                    distances[nextPage] = distance
                }

                if (!visited.contains(nextPage)) {
                    visited.add(nextPage)
                    queue.add(nextPage)
                }
            }
        }

        return distances
    }

    private fun getReachablePages(currentPage: String, distances: Map<String, Int>): Set<String> {
        val reachablePages = mutableSetOf<String>()
        for ((page, distance) in distances) {
            if (graph[currentPage]?.contains(page) == true || currentPage == page) {
                if (distance != Integer.MAX_VALUE) {
                    reachablePages.add(page)
                }
            }
        }
        return reachablePages
    }

    private fun getMostVisitedNextPage(pages: Set<String>): String {
        var mostVisitedPage = ""
        var highestVisitCount = -1
        for (page in pages) {
            val visitCount = visitCountMap[page]
            if (visitCount != null && visitCount > highestVisitCount) {
                highestVisitCount = visitCount
                mostVisitedPage = page
            }
        }
        return mostVisitedPage
    }
}
```

